3_real_world_example.code:
// 1. Create a custom event with some data payload
const cartEvent = new CustomEvent('itemAdded', {
  detail: { productId: 101, quantity: 2 },
  bubbles: true // By default, custom events do NOT bubble. We turn it on.
});

// 2. Somewhere else in the app, the Cart listens for this event
document.addEventListener('itemAdded', (e) => {
  console.log(`Updating cart with product ID: ${e.detail.productId}`);
});

// 3. When a user clicks a button, we fire the custom event
const btn = document.querySelector('.add-to-cart');
btn.addEventListener('click', () => {
  btn.dispatchEvent(cartEvent); 
});

